<?php session_start(); require 'db.php'; require 'functions.php'; if(!isset($_SESSION['user_id'])) exit; $me=$_SESSION['user_id']; $target=$_POST['following_id']; if($me!=$target){ $chk=$pdo->prepare("SELECT * FROM follows WHERE follower_id=? AND following_id=?"); $chk->execute([$me,$target]); if($chk->fetch()) $pdo->prepare("DELETE FROM follows WHERE follower_id=? AND following_id=?")->execute([$me,$target]); else { $pdo->prepare("INSERT INTO follows (follower_id, following_id) VALUES (?,?)")->execute([$me,$target]); createNotification($pdo,$target,$me,'follow',0); } } header("Location: profile.php?id=".$target); ?>
